"""
agentadmit.cli
--------------
CLI tool for AgentAdmit SDK setup.

Usage:
    agentadmit init          # Generate config file and keys
    agentadmit keys          # Generate/regenerate RS256 key pair
    agentadmit check         # Validate configuration
"""

import argparse
import os
import sys
from pathlib import Path


SAMPLE_CONFIG = '''# AgentAdmit Configuration
# Generated by: agentadmit init
# Docs: https://docs.agentadmit.app/sdk

# Your app identity
app_name: "My App"
app_id: ""                    # Get this from your AgentAdmit dashboard
api_base_url: "http://localhost:8000"  # Your app's base URL

# Key files (auto-generated by 'agentadmit init')
private_key_path: "keys/agentadmit_private.pem"
public_key_path: "keys/agentadmit_public.pem"

# Token settings
algorithm: "RS256"
audience: "agentadmit"
connection_token_ttl: 900     # 15 minutes for connection tokens

# Route prefix for AgentAdmit endpoints
route_prefix: "/agentadmit"

# User lookup — the field in your users table that stores the user ID
user_lookup_field: "user_id"  # Change to "id", "_id", "uid", etc. as needed

# Define your scopes — what can agents access?
# Each scope needs: name, description, category, role
scopes:
  # Example: User-facing scopes
  # - name: "read:orders"
  #   description: "View order history and delivery status"
  #   category: "Shopping"
  #   role: "user"
  #
  # - name: "create:orders"
  #   description: "Place new orders"
  #   category: "Shopping"
  #   role: "user"
  #
  # Example: Admin/Owner scopes
  # - name: "read:analytics"
  #   description: "View platform analytics and user metrics"
  #   category: "Admin"
  #   role: "admin"
  #
  # - name: "manage:inventory"
  #   description: "Update stock levels and product listings"
  #   category: "Admin"
  #   role: "admin"

# Connection duration options shown to users
durations:
  - label: "1 Hour"
    seconds: 3600
  - label: "24 Hours"
    seconds: 86400
  - label: "7 Days"
    seconds: 604800
  - label: "30 Days"
    seconds: 2592000
  - label: "Until I Revoke"
    seconds: null              # No expiry — user revokes manually

# Subscription tiers
tiers:
  - name: "trial"
    connections_limit: 3
    hard_cap: true             # Block at 3 connections
  - name: "standard"
    connections_limit: 100
    api_calls_monthly: 2000000
    hard_cap: false

default_tier: "standard"

# Storage backend
storage:
  backend: "mongodb"           # "mongodb" or "memory" (for testing)
  uri: "mongodb://localhost:27017"
  database: "your_database"    # Your app's database
  connections_collection: "agentadmit_connections"
  audit_log_collection: "agentadmit_audit_log"
  tokens_collection: "agentadmit_tokens"
'''


def cmd_init(args):
    """Generate config file and keys."""
    config_path = Path("agentadmit.yaml")

    if config_path.exists() and not args.force:
        print(f"Config file already exists: {config_path}")
        print("Use --force to overwrite.")
        return

    # Write config
    config_path.write_text(SAMPLE_CONFIG)
    print(f"Created: {config_path}")

    # Generate keys
    from agentadmit.keys import generate_key_pair
    priv, pub = generate_key_pair("keys")
    print(f"Created: {priv}")
    print(f"Created: {pub}")

    # Create .gitignore for keys
    gitignore = Path("keys/.gitignore")
    gitignore.write_text("*.pem\\n")
    print(f"Created: {gitignore}")

    print()
    print("Next steps:")
    print("  1. Edit agentadmit.yaml — define your scopes")
    print("  2. Add AgentAdmitMiddleware to your FastAPI app")
    print("  3. Add @require_scope_if_agent('your:scope') to protected routes")
    print()
    print("See: https://docs.agentadmit.app/sdk/quickstart")


def cmd_keys(args):
    """Generate or regenerate RS256 key pair."""
    from agentadmit.keys import generate_key_pair
    output = args.output or "keys"
    priv, pub = generate_key_pair(output)
    print(f"Generated: {priv}")
    print(f"Generated: {pub}")


def cmd_check(args):
    """Validate configuration."""
    config_path = args.config or "agentadmit.yaml"
    try:
        from agentadmit.config import load_config
        config = load_config(config_path)
        print(f"Config: {config_path}")
        print(f"App: {config.app_name}")
        print(f"Scopes: {len(config.scopes)}")
        print(f"Tiers: {len(config.tiers)}")
        print(f"Durations: {len(config.durations)}")
        print(f"Storage: {config.storage.backend}")

        # Check keys
        from agentadmit.keys import load_private_key, load_public_key
        try:
            load_private_key(config.private_key_path)
            load_public_key(config.public_key_path)
            print("Keys: OK")
        except Exception as e:
            print(f"Keys: MISSING ({e})")

        if len(config.scopes) == 0:
            print()
            print("WARNING: No scopes defined. Edit agentadmit.yaml to add scopes.")
        else:
            print()
            print("Scopes:")
            for s in config.scopes:
                print(f"  {s.name} — {s.description} [{s.category}/{s.role}]")

        print()
        print("Configuration is valid.")

    except Exception as e:
        print(f"Configuration error: {e}")
        sys.exit(1)


def main():
    parser = argparse.ArgumentParser(
        prog="agentadmit",
        description="AgentAdmit SDK — User-mediated AI agent authorization",
    )
    subparsers = parser.add_subparsers(dest="command")

    # init
    init_parser = subparsers.add_parser("init", help="Generate config file and keys")
    init_parser.add_argument("--force", action="store_true", help="Overwrite existing config")

    # keys
    keys_parser = subparsers.add_parser("keys", help="Generate RS256 key pair")
    keys_parser.add_argument("--output", "-o", help="Output directory (default: keys/)")

    # check
    check_parser = subparsers.add_parser("check", help="Validate configuration")
    check_parser.add_argument("--config", "-c", help="Config file path (default: agentadmit.yaml)")

    args = parser.parse_args()

    if args.command == "init":
        cmd_init(args)
    elif args.command == "keys":
        cmd_keys(args)
    elif args.command == "check":
        cmd_check(args)
    else:
        parser.print_help()


if __name__ == "__main__":
    main()
